class Solution {
    public int[] findOrder(int numCourses, int[][] prerequisites) {
        int[] res = new int[numCourses];
        int[] visited = new int[numCourses];
        int[] graph = new int[numCourses];
        int[][] edges = new int[numCourses][numCourses];
        int index = 0;

        for (int[] edge : prerequisites) {
            edges[edge[1]][graph[edge[1]]++] = edge[0];
        }

        for (int i = 0; i < numCourses; i++) {
            if (dfs(i, edges, graph, visited, res, index)) {
                return new int[0];
            }
        }

        return res;
    }

    private boolean dfs(int i, int[][] edges, int[] graph, int[] visited, int[] res, int index) {
        if (visited[i] == 1) {
            return true;
        }

        if (visited[i] == -1) {
            return false;
        }

        visited[i] = 1;

        for (int j = 0; j < graph[i]; j++) {
            if (dfs(edges[i][j], edges, graph, visited, res, index)) {
                return true;
            }
        }

        visited[i] = -1;
        res[index++] = i;

        return false;
    }
}

